import type { ComponentProps, ComponentPropsWithoutRef } from 'react';
import { useRender } from '@base-ui/react/use-render';
import clsx from 'clsx';
import styles from './Card.module.css';

type CardSize = 'default' | 'sm';
type CardTitleElement = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';

function Card({
  className,
  render,
  size = 'default',
  ...props
}: useRender.ComponentProps<'div'> & { size?: CardSize }) {
  return useRender({
    defaultTagName: 'div',
    render,
    props: {
      ...props,
      'data-slot': 'card',
      'data-size': size,
      className: clsx(styles.root, className),
    },
  });
}

function CardHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="card-header" className={clsx(styles.header, className)} {...props} />;
}

function CardContent({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="card-content" className={clsx(styles.content, className)} {...props} />;
}

function CardFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="card-footer" className={clsx(styles.footer, className)} {...props} />;
}

function CardTitle({
  as: Tag = 'h3',
  className,
  ...props
}: ComponentPropsWithoutRef<'h3'> & {
  as?: CardTitleElement;
}) {
  return <Tag data-slot="card-title" className={clsx(styles.title, className)} {...props} />;
}

function CardDescription({ className, ...props }: ComponentProps<'p'>) {
  return (
    <p data-slot="card-description" className={clsx(styles.description, className)} {...props} />
  );
}

function CardAction({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="card-action" className={clsx(styles.action, className)} {...props} />;
}

function CardLink({ className, render, ...props }: useRender.ComponentProps<'a'>) {
  return useRender({
    defaultTagName: 'a',
    render,
    props: {
      ...props,
      'data-slot': 'card-link',
      className: clsx(styles.link, className),
    },
  });
}

export {
  Card,
  CardHeader,
  CardContent,
  CardFooter,
  CardTitle,
  CardDescription,
  CardAction,
  CardLink,
};
export type { CardSize, CardTitleElement };

@layer ui.components {
  .root {
    --card-padding-default: var(--card-padding, var(--spacing-6));
    --card-title-font-size-default: var(--card-title-font-size, var(--text-lg));
    --card-title-line-height-default: var(--card-title-line-height, var(--line-height-text-lg));

    box-sizing: border-box;
    position: relative;
    display: flex;
    width: 100%;
    min-width: 0;
    flex-direction: column;
    border: var(--card-border-width, var(--border-width-sm)) solid
      var(--card-border-color, var(--color-border));
    border-radius: var(--card-radius, var(--radius-lg));
    background-color: var(--card-bg, var(--color-card));
    color: var(--card-color, var(--color-card-foreground));
    box-shadow: var(--card-shadow, none);

    &:where(a) {
      text-decoration: none;
    }

    &[data-size='sm'] {
      --card-padding-default: var(--card-padding-sm, var(--spacing-4));
      --card-title-font-size-default: var(--card-title-font-size-sm, var(--text-md));
      --card-title-line-height-default: var(
        --card-title-line-height-sm,
        var(--line-height-text-md)
      );
    }

    &:has([data-slot='card-link'])
      :where(
        a,
        button,
        input,
        select,
        textarea,
        [role='button'],
        [role='checkbox'],
        [role='menuitem'],
        [role='switch'],
        [tabindex]:not([tabindex='-1'])
      ):not([data-slot='card-link']) {
      position: relative;
      z-index: 1;
    }
  }

  .header,
  .content,
  .footer {
    box-sizing: border-box;
    min-width: 0;
    padding-inline: var(--card-padding-default);
  }

  .header {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    column-gap: var(--card-action-gap, var(--spacing-2));
    row-gap: var(--card-header-gap, var(--spacing-1));
    padding-block: var(--card-padding-default) 0;
  }

  .content {
    padding-block: var(--card-content-padding-top, var(--spacing-4)) var(--card-padding-default);
    color: var(--card-content-color, var(--color-muted-foreground));
    font-size: var(--card-content-font-size, var(--text-sm));
    line-height: var(--card-content-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;

    &:first-child {
      padding-block-start: var(--card-padding-default);
    }

    & > :first-child {
      margin-top: 0;
    }

    & > :last-child {
      margin-bottom: 0;
    }
  }

  .footer {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: var(--card-footer-gap, var(--spacing-2));
    padding-block: 0 var(--card-padding-default);
  }

  .title {
    grid-column: 1;
    margin: 0;
    min-width: 0;
    color: var(--card-title-color, currentColor);
    font-size: var(--card-title-font-size-default);
    font-weight: var(--card-title-font-weight, var(--weight-semibold));
    line-height: var(--card-title-line-height-default);
    overflow-wrap: anywhere;
  }

  .description {
    grid-column: 1;
    margin: 0;
    min-width: 0;
    color: var(--card-description-color, var(--color-muted-foreground));
    font-size: var(--card-description-font-size, var(--text-sm));
    line-height: var(--card-description-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;
  }

  .action {
    position: relative;
    z-index: 1;
    grid-column: 2;
    grid-row: 1 / span 2;
    display: inline-flex;
    align-items: start;
    justify-content: flex-end;
    gap: var(--card-action-gap, var(--spacing-2));
    justify-self: end;
  }

  .link {
    position: static;
    color: inherit;
    text-decoration: none;

    &::after {
      content: '';
      position: absolute;
      z-index: 0;
      inset: 0;
      border-radius: var(--card-radius, var(--radius-lg));
    }

    &:focus-visible {
      outline: 0;
    }

    &:focus-visible::after {
      outline: var(--card-focus-ring-width, var(--border-width-md)) solid
        var(--card-focus-ring-color, var(--color-ring));
      outline-offset: var(--card-focus-ring-offset, var(--border-width-sm));
    }
  }
}

export {
  Card,
  CardHeader,
  CardContent,
  CardFooter,
  CardTitle,
  CardDescription,
  CardAction,
  CardLink,
} from './Card';
export type { CardSize, CardTitleElement } from './Card';
